public class SafePow {
    static long pow(long base, int exp) {
        if (exp == 0) return 1;
        return base * pow(base, exp - 1);
    }
    public static void main(String[] args) {
        System.out.println(pow(2, 10));
        System.out.println(pow(2, -1));  // StackOverflow!
    }
}
